{"content":"import cv2
import numpy as np

def downsample_image(image, scale_factor):
    """
    Downsamples the image by a given scale factor.
    Useful for speeding up coarse detection on large images (e.g., 30k x 30k).
    """
    if scale_factor <= 1:
        return image
    new_width = int(image.shape[1] / scale_factor)
    new_height = int(image.shape[0] / scale_factor)
    return cv2.resize(image, (new_width, new_height), interpolation=cv2.INTER_AREA)

def apply_gaussian_blur(image, kernel_size=(5, 5), sigma=0):
    """Applies Gaussian blur to the image to reduce noise."""
    return cv2.GaussianBlur(image, kernel_size, sigma)

def subtract_background(image, background):
    """Subtracts background from the image."""
    return cv2.absdiff(image, background)

def preprocess_for_coarse(image, scale_factor=10):
    """Preprocesses the image for coarse detection."""
    downsampled = downsample_image(image, scale_factor)
    blurred = apply_gaussian_blur(downsampled)
    return blurred

def extract_region(image, center, radius, margin=100):
    """Extract a region of interest around the detected circle."""
    x, y = int(center[0]), int(center[1])
    r = int(radius)
    h, w = image.shape[:2]

    x1 = max(0, x - r - margin)
    y1 = max(0, y - r - margin)
    x2 = min(w, x + r + margin)
    y2 = min(h, y + r + margin)

    return image[y1:y2, x1:x2], (x1, y1)
